using namespace std;

#define MOD 1000000009

long long w,h,n;

struct Matrix{

    long long n,m[80][80];

    Matrix  operator * (const Matrix &b)const{

        Matrix c;

        memset(c.m,0,sizeof c.m);

        c.n=n;

        for (int i=0;i<n;i++)

        for (int j=0;j<n;j++)

        for (int k=0;k<n;k++){

            c.m[i][j]=(c.m[i][j]+(m[i][k]*b.m[k][j])%MOD)%MOD;

        }

        return c;

    }

};

Matrix ones;

Matrix Pow(const Matrix &a,unsigned long long n){

    Matrix t=ones,y=a;

    while (n){

        if (n & 1) t = (t * y) ;

        y = (y * y) ;

        n /= 2;

    }

    return t;

}

Matrix A;

long long x[80];

long long k,p,q;

struct node{

    long long a,b;

};

node Pos[80];

int cmp(node a,node b){

    return a.b<b.b;

}

void get_x(Matrix a){

    long long y[80];

    memset(y,0,sizeof y);

    for (int i=0;i<a.n;i++){

        for (int j=0;j<a.n;j++){

            y[i]=(y[i]+(x[j]*a.m[i][j])%MOD)%MOD;

        }

    }

    for (int i=0;i<a.n;i++)

        x[i]=y[i];

}

int main(){

    int i,j;

    int d=0;

    while (scanf("%lld%lld%lld",&w,&h,&n)!=EOF){

