        x[0]=1;

        memset(A.m,0,sizeof A.m);

        A.n=w;

        A.m[0][0]=1;

        A.m[0][1]=1;

        for (i=1;i<w;i++){

            A.m[i][i]=1;

            A.m[i][i-1]=1;

            A.m[i][i+1]=1;

        }

        k=0;

        j=0;

